bool Notifications::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id"))
    {
        if(!validJsonOfField(0, "id", pJson["id"], err, true))
            return false;
    }
    if(pJson.isMember("notification_id"))
    {
        if(!validJsonOfField(1, "notification_id", pJson["notification_id"], err, true))
            return false;
    }
    else
    {
        err="The notification_id column cannot be null";
        return false;
    }
    if(pJson.isMember("actor_uid"))
    {
        if(!validJsonOfField(2, "actor_uid", pJson["actor_uid"], err, true))
            return false;
    }
    else
    {
        err="The actor_uid column cannot be null";
        return false;
    }
    if(pJson.isMember("reactor_uid"))
    {
        if(!validJsonOfField(3, "reactor_uid", pJson["reactor_uid"], err, true))
            return false;
    }
    else
    {
        err="The reactor_uid column cannot be null";
        return false;
    }
    if(pJson.isMember("action_type"))
    {
        if(!validJsonOfField(4, "action_type", pJson["action_type"], err, true))
            return false;
    }
    else
    {
        err="The action_type column cannot be null";
        return false;
    }
    if(pJson.isMember("content"))
    {
        if(!validJsonOfField(5, "content", pJson["content"], err, true))
            return false;
    }
    else
    {
        err="The content column cannot be null";
        return false;
    }
    if(pJson.isMember("status"))
    {
        if(!validJsonOfField(6, "status", pJson["status"], err, true))
            return false;
    }
    if(pJson.isMember("create_time"))
    {
        if(!validJsonOfField(7, "create_time", pJson["create_time"], err, true))
            return false;
    }
    return true;
}
